# api/middleware/auth.py
import uuid
import os

class IAMSkeleton:
    def __init__(self):
        self._tokens: dict[str, float] = {}       # token → created_at
        self._state_tree: dict[str, dict] = {}     # token → {session_id → state}
        # 管理员 token 列表，从环境变量读取
        self._admin_tokens: set[str] = set()
        admin_env = os.environ.get("ADMIN_TOKENS", "")
        if admin_env:
            for t in admin_env.split(","):
                self._admin_tokens.add(t.strip())

    def issue_anonymous_token(self) -> str:
        token = str(uuid.uuid4())
        self._tokens[token] = time.time()
        return token

    def validate_token(self, token: str) -> bool:
        return token in self._tokens

    def is_admin(self, token: str) -> bool:
        return token in self._admin_tokens

    def get_session_tree(self, token: str, session_id: str) -> dict:
        return self._state_tree.get(token, {}).get(session_id, {})
