# api/services/dashboard_aggregator.py
class DashboardAggregator:
    def __init__(self):
        self._cfg_path = self._resolve_cfg_path()

    def get_ttm_radar(self, session_id: str) -> dict[str, float]:
        """返回 TTM 五维倾向性评分"""
        ttm_stage = CoachBridge.get_ttm_stage(session_id)
        if ttm_stage is None or ttm_stage == "unknown":
            return self._default_ttm_radar()
        # 映射当前阶段 → 五维向量
        stage_profile = TTM_STAGE_VECTORS.get(ttm_stage, self._default_ttm_radar())
        return stage_profile

    def get_sdt_rings(self, session_id: str) -> dict[str, float]:
        """返回 SDT 三核评分"""
        return CoachBridge.get_sdt_scores(session_id)

    def get_progress(self, session_id: str) -> dict:
        """返回学习进度摘要"""
        # 从 CoachAgent 读取交互历史统计
        return {"total_sessions": 1, "total_turns": 0, "no_assist_avg": None}
